export type SequenceInput = {
  occurrenceId: string;
  sequence: string;
};

export type ClassificationItem = {
  key: number;
  name: string;
  rank: string;
};

export type TaxonMatch = {
  synonym?: boolean;
  usage?: {
    key: number;
    name: string;
    rank?: string;
    formattedName?: string;
  };
  classification?: ClassificationItem[];
  diagnostics?: {
    matchType?: string;
    confidence?: number;
    status?: string;
  };
};

export type BlastMatch = {
  name?: string;
  identity?: number;
  appliedScientificName?: string;
  matchType?: string;
  bitScore?: number;
  expectValue?: number;
  querySequence?: string;
  subjectSequence?: string;
  qstart?: string;
  qend?: string;
  sstart?: string;
  send?: string;
  qcovs?: number;
  distanceToBestMatch?: number;
  accession?: string;
  taxonMatch?: TaxonMatch;
  /** True when the GBIF taxonomy lookup failed (network/server error). Absent when lookup succeeded (even with no match). */
  taxonMatchError?: boolean;
};

export type SequenceResult = {
  occurrenceId: string;
  sequence: string;
  marker: string;
  status: 'pending' | 'matched' | 'errored';
  match?: BlastMatch;
  error?: string;
};

export type Phase = 'upload' | 'results';
export type SortDirection = 'asc' | 'desc';

export type ResultColumn = {
  key: string;
  id: string;
  defaultMessage: string;
  /** Optional help text shown in a tooltip next to the column header. */
  help?: string;
  helpId?: string;
};

